using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class IngredientSubstitutionConfiguration : IEntityTypeConfiguration<IngredientSubstitution>{public void Configure(EntityTypeBuilder<IngredientSubstitution> builder){builder.ToTable("ingredient_substitutions");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("substitution_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.Reason).HasConversion<string>().HasMaxLength(30);builder.Property(e => e.CostSavingsPercent).HasColumnType("decimal(5,2)");builder.HasOne(e => e.OriginalIngredient).WithMany().HasForeignKey(e => e.OriginalIngredientId).OnDelete(DeleteBehavior.Cascade);builder.HasOne(e => e.Replacement).WithMany().HasForeignKey(e => e.ReplacementId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.OriginalIngredientId, e.ReplacementId }).IsUnique();}}
